  "code": "    best_strength = -float('inf')
    best_ext = None
    for ext in extensions:
        upper = sum(1 for ch in ext if ch.isupper())
        lower = sum(1 for ch in ext if ch.islower())
        strength = upper - lower
        if strength > best_strength:
